// A03: SQL Injection — NEVER concatenate user input
String bad = "SELECT * FROM users WHERE name = '" + input + "'";
// Input: ' OR '1'='1 → dumps entire table

// Fix: prepared statements
PreparedStatement ps = conn.prepareStatement(
    "SELECT * FROM users WHERE name = ?");
ps.setString(1, input); // input is parameterized, not concatenated

// JPA is safe IF you use parameters:
// Safe:
@Query("SELECT u FROM User u WHERE u.email = :email")
User findByEmail(@Param("email") String email);

// UNSAFE (native query with string concat):
@Query(value = "SELECT * FROM users WHERE email = '" + email + "'",
       nativeQuery = true) // DON'T DO THIS

// A01: Broken Access Control — always check ownership
@GetMapping("/orders/{id}")
public Order getOrder(@PathVariable long id, Principal principal) {
    Order order = orderService.findById(id);
    if (!order.getOwnerEmail().equals(principal.getName())) {
        throw new ResponseStatusException(HttpStatus.FORBIDDEN);
    }
    return order;
}

// JWT structure: header.payload.signature
// Header: {"alg":"RS256","typ":"JWT"}
// Payload: {"sub":"user@example.com","exp":1735689600,"roles":["USER"]}
// Signature: RSA sign(base64(header) + "." + base64(payload), privateKey)

// Spring Security: validate JWT on every request
@Bean
public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
    return http
        .oauth2ResourceServer(oauth2 -> oauth2
            .jwt(jwt -> jwt.decoder(jwtDecoder()))) // validates signature + expiry
        .authorizeHttpRequests(auth -> auth
            .requestMatchers("/public/**").permitAll()
            .anyRequest().authenticated())
        .build();
}

// Decode and read claims
@GetMapping("/profile")
public ProfileDto getProfile(@AuthenticationPrincipal Jwt jwt) {
    String email = jwt.getSubject();
    List<String> roles = jwt.getClaimAsStringList("roles");
    return profileService.findByEmail(email);
}

// Refresh tokens: short-lived access token (15 min) + long-lived refresh token (7 days)
// On expiry: client sends refresh token → server issues new access token
// On logout: add access token to a blocklist (Redis) until expiry

// Bean Validation on request DTO
public class CreateUserRequest {
    @NotBlank
    @Size(min = 2, max = 50)
    private String name;

    @Email
    @NotBlank
    private String email;

    @Pattern(regexp = "^[a-zA-Z0-9]{8,}$",
             message = "Password must be alphanumeric and at least 8 characters")
    private String password;
}

// Spring MVC: @Valid triggers validation, BindingResult captures errors
@PostMapping("/users")
public ResponseEntity<?> create(@Valid @RequestBody CreateUserRequest req,
                                BindingResult errors) {
    if (errors.hasErrors()) {
        return ResponseEntity.badRequest().body(errors.getAllErrors());
    }
    return ResponseEntity.status(201).body(userService.create(req));
}

// Never trust path variables either
@GetMapping("/files/{filename}")
public Resource getFile(@PathVariable String filename) {
    // BAD: path traversal — filename = "../../etc/passwd"
    // GOOD: validate and sanitize
    if (filename.contains("..") || filename.contains("/")) {
        throw new ResponseStatusException(HttpStatus.BAD_REQUEST);
    }
    return storageService.load(filename);
}

