// BETTER: Spring Cloud Config / AWS SSM
// bootstrap.yml:
spring.cloud.config.uri: http://config-server:8888
# Config server reads from Git or Vault

// BEST: AWS Secrets Manager (auto-rotation)
@Bean
public AWSSecretsManager secretsManager() {
    return AWSSecretsManagerClientBuilder.standard().build();
}

public String getDbPassword() {
    GetSecretValueRequest req = new GetSecretValueRequest()
        .withSecretId("prod/myapp/db");
    return secretsManager.getSecretValue(req).getSecretString();
    // Cached by AWS SDK — no latency on every call
}

